import{_ as r,o as e,c as o,a2 as a}from"./chunks/framework.DGDNmojq.js";const p=JSON.parse('{"title":"后端框架生态 (Backend Frameworks)","description":"JavaScript/TypeScript 后端框架生态 (Backend Frameworks) 完整指南","frontmatter":{"title":"后端框架生态 (Backend Frameworks)","description":"JavaScript/TypeScript 后端框架生态 (Backend Frameworks) 完整指南"},"headers":[],"relativePath":"categories/backend-frameworks.md","filePath":"categories/backend-frameworks.md","lastUpdated":1776726957000}'),d={name:"categories/backend-frameworks.md"};function s(l,t,i,n,h,g){return e(),o("div",null,[...t[0]||(t[0]=[a('<h2 id="🧪-关联代码实验室" tabindex="-1">🧪 关联代码实验室 <a class="header-anchor" href="#🧪-关联代码实验室" aria-label="Permalink to &quot;🧪 关联代码实验室&quot;">​</a></h2><blockquote><p><strong>1</strong> 个关联模块 · 平均成熟度：<strong>🌳</strong></p></blockquote><table tabindex="0"><thead><tr><th>模块</th><th>成熟度</th><th>实现文件</th><th>测试文件</th></tr></thead><tbody><tr><td><a href="./../../jsts-code-lab/19-backend-development/">19-backend-development</a></td><td>🌳</td><td>3</td><td>3</td></tr></tbody></table><blockquote><p>本文档梳理 Node.js 及现代 JavaScript 运行时后端框架，数据参考自 GitHub Stars、JavaScript Rising Stars 2024/2025 及 npm 下载趋势</p></blockquote><hr><h2 id="📊-生态概览" tabindex="-1">📊 生态概览 <a class="header-anchor" href="#📊-生态概览" aria-label="Permalink to &quot;📊 生态概览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>框架</th><th>Stars</th><th>趋势</th><th>定位</th></tr></thead><tbody><tr><td>Express</td><td>67k+</td><td>⭐ 标准稳定</td><td>Web框架标准</td></tr><tr><td>Fastify</td><td>31k+</td><td>⭐ 性能优先</td><td>极速低开销框架</td></tr><tr><td>Nest</td><td>65k+</td><td>⭐ 企业级</td><td>企业级全栈框架</td></tr><tr><td>Koa</td><td>35k+</td><td>⭐ 经典稳定</td><td>下一代Web框架</td></tr><tr><td>Hono</td><td>28k+</td><td>🚀 快速崛起</td><td>边缘优先框架</td></tr><tr><td>tRPC</td><td>35k+</td><td>⭐ 类型安全</td><td>端到端类型安全RPC</td></tr><tr><td>Socket.io</td><td>61k+</td><td>⭐ 实时通信</td><td>实时通信标准</td></tr><tr><td>hapi</td><td>14k+</td><td>⭐ 成熟稳定</td><td>企业级框架</td></tr><tr><td>Elysia</td><td>19k+</td><td>🚀 新兴热门</td><td>Bun优先框架</td></tr></tbody></table><hr><h2 id="_1-node-js-传统框架" tabindex="-1">1. Node.js 传统框架 <a class="header-anchor" href="#_1-node-js-传统框架" aria-label="Permalink to &quot;1. Node.js 传统框架&quot;">​</a></h2><h3 id="express" tabindex="-1">Express <a class="header-anchor" href="#express" aria-label="Permalink to &quot;Express&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Express</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 67,000+</td></tr><tr><td><strong>TS支持</strong></td><td>⚠️ 需 @types/express</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/expressjs/express" target="_blank" rel="noreferrer">expressjs/express</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://expressjs.com" target="_blank" rel="noreferrer">expressjs.com</a></td></tr><tr><td><strong>npm</strong></td><td>每周下载 2500万+</td></tr></tbody></table><p><strong>一句话描述</strong>：Node.js Web 框架的事实标准，极简、灵活、生态最丰富。</p><p><strong>核心特点</strong>：</p><ul><li>极简核心，中间件机制成熟</li><li>庞大的生态系统，中间件数量最多</li><li>学习曲线平缓，文档丰富</li><li>2024年发布 v5.0，2025年 v5.1.0 持续维护</li><li>加入 OpenJS Foundation，治理结构完善</li></ul><p><strong>适用场景</strong>：</p><ul><li>中小型 Web 应用和 API</li><li>需要丰富中间件生态的项目</li><li>快速原型开发</li><li>遗留项目维护</li></ul><hr><h3 id="fastify" tabindex="-1">Fastify <a class="header-anchor" href="#fastify" aria-label="Permalink to &quot;Fastify&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Fastify</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 31,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/fastify/fastify" target="_blank" rel="noreferrer">fastify/fastify</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://fastify.io" target="_blank" rel="noreferrer">fastify.io</a></td></tr><tr><td><strong>npm</strong></td><td>每月下载 780万+</td></tr></tbody></table><p><strong>一句话描述</strong>：专注于性能和企业级开发者体验的低开销 Web 框架。</p><p><strong>核心特点</strong>：</p><ul><li>极高性能：每秒可处理 7.6万+ 请求（比 Express 快 5倍）</li><li>JSON Schema 验证：内置高性能验证和序列化</li><li>强大的插件架构：解耦的插件系统</li><li>内置日志：集成 Pino 日志库</li><li>TypeScript 原生支持</li><li>2024年9月发布 v5.0</li></ul><p><strong>适用场景</strong>：</p><ul><li>高性能 API 服务</li><li>微服务架构</li><li>对延迟敏感的应用</li><li>需要类型安全的大型项目</li></ul><hr><h3 id="nestjs" tabindex="-1">NestJS <a class="header-anchor" href="#nestjs" aria-label="Permalink to &quot;NestJS&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>NestJS</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 65,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生 TypeScript</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/nestjs/nest" target="_blank" rel="noreferrer">nestjs/nest</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://nestjs.com" target="_blank" rel="noreferrer">nestjs.com</a></td></tr><tr><td><strong>npm</strong></td><td>每月下载 500万+</td></tr></tbody></table><p><strong>一句话描述</strong>：企业级 Node.js 框架，受 Angular 启发，提供完整的架构解决方案。</p><p><strong>核心特点</strong>：</p><ul><li>模块化架构：依赖注入、装饰器模式</li><li>完整的生态：支持 GraphQL、WebSocket、Microservices</li><li>开箱即用的企业级功能：认证、授权、配置、日志</li><li>支持多种 HTTP 框架：Express 或 Fastify 作为底层</li><li>优秀的测试支持</li></ul><p><strong>适用场景</strong>：</p><ul><li>大型企业级后端应用</li><li>微服务架构</li><li>需要严格架构规范的项目</li><li>团队协作开发</li></ul><hr><h3 id="koa" tabindex="-1">Koa <a class="header-anchor" href="#koa" aria-label="Permalink to &quot;Koa&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Koa</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 35,000+</td></tr><tr><td><strong>TS支持</strong></td><td>⚠️ 需 @types/koa</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/koajs/koa" target="_blank" rel="noreferrer">koajs/koa</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://koajs.com" target="_blank" rel="noreferrer">koajs.com</a></td></tr></tbody></table><p><strong>一句话描述</strong>：Express 团队打造的下一代 Web 框架，基于 async/await。</p><p><strong>核心特点</strong>：</p><ul><li>更小的内核，更强大的表现力</li><li>中间件基于 async/await，告别回调地狱</li><li>没有内置中间件，极度灵活</li><li>轻量级，核心代码约 2000 行</li></ul><p><strong>适用场景</strong>：</p><ul><li>需要精细控制中间件的项目</li><li>异步流程复杂的应用</li><li>轻量级 API 服务</li></ul><hr><h3 id="hapi" tabindex="-1">hapi <a class="header-anchor" href="#hapi" aria-label="Permalink to &quot;hapi&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>hapi</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 14,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 社区类型定义</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/hapijs/hapi" target="_blank" rel="noreferrer">hapijs/hapi</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://hapi.dev" target="_blank" rel="noreferrer">hapi.dev</a></td></tr></tbody></table><p><strong>一句话描述</strong>：企业级应用框架，强调配置优于编码，提供完整的业务逻辑分离。</p><p><strong>核心特点</strong>：</p><ul><li>配置驱动的开发模式</li><li>内置输入验证（Joi）</li><li>强大的插件系统</li><li>完善的错误处理</li><li>适合大型团队协作</li></ul><p><strong>适用场景</strong>：</p><ul><li>大型企业级应用</li><li>需要严格输入验证的 API</li><li>团队协作项目</li></ul><hr><h3 id="restify" tabindex="-1">Restify <a class="header-anchor" href="#restify" aria-label="Permalink to &quot;Restify&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>restify</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 11,000+</td></tr><tr><td><strong>TS支持</strong></td><td>⚠️ 需 @types/restify</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/restify/node-restify" target="_blank" rel="noreferrer">restify/node-restify</a></td></tr><tr><td><strong>官网</strong></td><td><a href="http://restify.com" target="_blank" rel="noreferrer">restify.com</a></td></tr></tbody></table><p><strong>一句话描述</strong>：专为构建语义正确的 RESTful Web 服务而优化的框架。</p><p><strong>核心特点</strong>：</p><ul><li>DTrace 内置支持（性能追踪）</li><li>语义版本化路由</li><li>内容协商和格式化</li><li>专注于 REST API 构建</li></ul><p><strong>适用场景</strong>：</p><ul><li>严格的 RESTful API 服务</li><li>需要 DTrace 监控的生产环境</li><li>JSON API 服务</li></ul><hr><h3 id="micro" tabindex="-1">micro <a class="header-anchor" href="#micro" aria-label="Permalink to &quot;micro&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>micro</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 10,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/vercel/micro" target="_blank" rel="noreferrer">vercel/micro</a></td></tr></tbody></table><p><strong>一句话描述</strong>：异步 HTTP 微服务框架，Vercel 出品，极简设计。</p><p><strong>核心特点</strong>：</p><ul><li>单文件微服务</li><li>自动解析 JSON 请求/响应</li><li>内置错误处理</li><li>专为 Serverless 优化</li></ul><p><strong>适用场景</strong>：</p><ul><li>微服务架构</li><li>Serverless 函数</li><li>轻量级 HTTP 服务</li></ul><hr><h2 id="_2-新兴运行时框架" tabindex="-1">2. 新兴运行时框架 <a class="header-anchor" href="#_2-新兴运行时框架" aria-label="Permalink to &quot;2. 新兴运行时框架&quot;">​</a></h2><h3 id="hono" tabindex="-1">Hono <a class="header-anchor" href="#hono" aria-label="Permalink to &quot;Hono&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Hono</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 28,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/honojs/hono" target="_blank" rel="noreferrer">honojs/hono</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://hono.dev" target="_blank" rel="noreferrer">hono.dev</a></td></tr></tbody></table><p><strong>一句话描述</strong>：基于 Web 标准的极速、轻量 Web 框架，可运行在任何 JavaScript 运行时。</p><p><strong>核心特点</strong>：</p><ul><li>边缘优先：支持 Cloudflare Workers、Deno、Bun、Node.js</li><li>基于 Fetch API 和 Web 标准</li><li>极小的包体积（~14KB）</li><li>与 Express 类似的 API 设计</li><li>内置中间件生态（CORS、缓存、验证等）</li><li>JavaScript Rising Stars 2025 增长最快框架之一</li></ul><p><strong>适用场景</strong>：</p><ul><li>边缘计算和 Serverless</li><li>Cloudflare Workers 开发</li><li>跨平台部署需求</li><li>追求极致性能的新项目</li></ul><hr><h3 id="elysia" tabindex="-1">Elysia <a class="header-anchor" href="#elysia" aria-label="Permalink to &quot;Elysia&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Elysia</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 19,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持，类型推断出色</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/elysiajs/elysia" target="_blank" rel="noreferrer">elysiajs/elysia</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://elysiajs.com" target="_blank" rel="noreferrer">elysiajs.com</a></td></tr></tbody></table><p><strong>一句话描述</strong>：以 Bun 为首选运行时的 TypeScript 框架，追求人体工程学和性能。</p><p><strong>核心特点</strong>：</p><ul><li>Bun 优先优化，性能出色</li><li>流式接口（Fluent API）设计</li><li>静态代码分析优化（Sucrose）</li><li>端到端类型安全</li><li>类似 Fastify 的插件系统</li><li>2024年3月发布 v1.0 稳定版</li></ul><p><strong>适用场景</strong>：</p><ul><li>Bun 运行时项目</li><li>追求极致性能的应用</li><li>需要强类型约束的项目</li></ul><hr><h3 id="nitro" tabindex="-1">Nitro <a class="header-anchor" href="#nitro" aria-label="Permalink to &quot;Nitro&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Nitro</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 5,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/unjs/nitro" target="_blank" rel="noreferrer">unjs/nitro</a></td></tr><tr><td><strong>文档</strong></td><td><a href="https://nitro.unjs.io" target="_blank" rel="noreferrer">nitro.unjs.io</a></td></tr></tbody></table><p><strong>一句话描述</strong>：通用的服务端引擎，Nuxt 3 的底层核心，支持多种部署目标。</p><p><strong>核心特点</strong>：</p><ul><li>基于 H3（HTTP 框架）构建</li><li>文件系统路由</li><li>多平台部署：Node.js、Deno、Cloudflare Workers、Vercel 等</li><li>自动代码分割</li><li>存储抽象层（Key-Value、FS 等）</li><li>属于 UnJS 生态</li></ul><p><strong>适用场景</strong>：</p><ul><li>Nuxt 3 服务端开发</li><li>需要多平台部署的服务端应用</li><li>全栈框架构建</li></ul><hr><h2 id="_3-全栈-元框架" tabindex="-1">3. 全栈/元框架 <a class="header-anchor" href="#_3-全栈-元框架" aria-label="Permalink to &quot;3. 全栈/元框架&quot;">​</a></h2><h3 id="next-js-api-routes" tabindex="-1">Next.js API Routes <a class="header-anchor" href="#next-js-api-routes" aria-label="Permalink to &quot;Next.js API Routes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Next.js</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 137,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/vercel/next.js" target="_blank" rel="noreferrer">vercel/next.js</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://nextjs.org" target="_blank" rel="noreferrer">nextjs.org</a></td></tr></tbody></table><p><strong>一句话描述</strong>：React 全栈框架，提供 Pages Router 和 App Router 两种 API 路由方案。</p><p><strong>核心特点</strong>：</p><ul><li>Pages Router：传统 <code>/pages/api</code> 路由</li><li>App Router：基于 React Server Components 的 Route Handlers</li><li>边缘运行时支持</li><li>内置 API 中间件</li><li>与前端深度集成</li></ul><p><strong>适用场景</strong>：</p><ul><li>全栈 React 应用</li><li>需要前后端同构的项目</li><li>边缘部署需求</li></ul><hr><h3 id="nuxt-server" tabindex="-1">Nuxt Server <a class="header-anchor" href="#nuxt-server" aria-label="Permalink to &quot;Nuxt Server&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Nuxt</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 55,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/nuxt/nuxt" target="_blank" rel="noreferrer">nuxt/nuxt</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://nuxt.com" target="_blank" rel="noreferrer">nuxt.com</a></td></tr></tbody></table><p><strong>一句话描述</strong>：Vue 全栈框架，基于 Nitro 引擎提供服务端能力。</p><p><strong>核心特点</strong>：</p><ul><li>Server API：<code>~/server/api</code> 自动路由</li><li>Server Middleware：请求拦截处理</li><li>Server Utils：工具函数集合</li><li>与 Nitro 深度集成</li><li>支持多种渲染模式</li></ul><p><strong>适用场景</strong>：</p><ul><li>全栈 Vue 应用</li><li>需要服务端渲染的项目</li></ul><hr><h3 id="sveltekit" tabindex="-1">SvelteKit <a class="header-anchor" href="#sveltekit" aria-label="Permalink to &quot;SvelteKit&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>SvelteKit</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 18,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/sveltejs/kit" target="_blank" rel="noreferrer">sveltejs/kit</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://kit.svelte.dev" target="_blank" rel="noreferrer">kit.svelte.dev</a></td></tr></tbody></table><p><strong>一句话描述</strong>：Svelte 的官方全栈框架，提供服务端路由和数据获取。</p><p><strong>核心特点</strong>：</p><ul><li>文件系统路由 + <code>+server.js</code> 端点</li><li>表单 actions 和渐进增强</li><li>多种适配器：Node、Vercel、Netlify、Cloudflare 等</li><li>基于 Web 标准的 Request/Response</li></ul><p><strong>适用场景</strong>：</p><ul><li>全栈 Svelte 应用</li><li>边缘部署</li></ul><hr><h2 id="_4-实时-通信框架" tabindex="-1">4. 实时/通信框架 <a class="header-anchor" href="#_4-实时-通信框架" aria-label="Permalink to &quot;4. 实时/通信框架&quot;">​</a></h2><h3 id="socket-io" tabindex="-1">Socket.io <a class="header-anchor" href="#socket-io" aria-label="Permalink to &quot;Socket.io&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>Socket.io</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 61,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生支持</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/socketio/socket.io" target="_blank" rel="noreferrer">socketio/socket.io</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://socket.io" target="_blank" rel="noreferrer">socket.io</a></td></tr></tbody></table><p><strong>一句话描述</strong>：实时双向通信库的标准，支持 WebSocket 和长轮询自动降级。</p><p><strong>核心特点</strong>：</p><ul><li>自动传输降级（WebSocket → 长轮询）</li><li>房间（Room）和命名空间（Namespace）支持</li><li>自动重连和心跳检测</li><li>支持二进制数据</li><li>跨浏览器兼容</li><li>服务端和客户端配对使用</li></ul><p><strong>适用场景</strong>：</p><ul><li>实时聊天应用</li><li>协作编辑工具</li><li>实时数据推送</li><li>游戏服务器</li></ul><hr><h3 id="ws" tabindex="-1">ws <a class="header-anchor" href="#ws" aria-label="Permalink to &quot;ws&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>ws</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 22,000+</td></tr><tr><td><strong>TS支持</strong></td><td>⚠️ 需 @types/ws</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/websockets/ws" target="_blank" rel="noreferrer">websockets/ws</a></td></tr></tbody></table><p><strong>一句话描述</strong>：Node.js 最快的 WebSocket 库，简洁高效。</p><p><strong>核心特点</strong>：</p><ul><li>纯 WebSocket 实现，无降级机制</li><li>极高的性能和低内存占用</li><li>简洁的 API</li><li>支持 permessage-deflate 压缩</li></ul><p><strong>适用场景</strong>：</p><ul><li>纯 WebSocket 应用</li><li>对性能要求极高的场景</li><li>游戏和实时数据流</li></ul><hr><h3 id="uwebsockets-js" tabindex="-1">uWebSockets.js <a class="header-anchor" href="#uwebsockets-js" aria-label="Permalink to &quot;uWebSockets.js&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>uWebSockets.js</td></tr><tr><td><strong>TS支持</strong></td><td>⚠️ 社区类型定义</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/uNetworking/uWebSockets.js" target="_blank" rel="noreferrer">uNetworking/uWebSockets.js</a></td></tr></tbody></table><p><strong>一句话描述</strong>：基于 C++ 的极速 WebSocket 和 HTTP 服务器实现。</p><p><strong>核心特点</strong>：</p><ul><li>C++ 核心，Node.js 绑定</li><li>业界最快的 WebSocket 实现</li><li>支持 SSL/TLS</li><li>Pub/Sub 内置支持</li></ul><p><strong>适用场景</strong>：</p><ul><li>超高并发 WebSocket 服务</li><li>金融交易系统</li><li>高频实时数据</li></ul><hr><h2 id="_5-rpc-框架" tabindex="-1">5. RPC 框架 <a class="header-anchor" href="#_5-rpc-框架" aria-label="Permalink to &quot;5. RPC 框架&quot;">​</a></h2><h3 id="trpc" tabindex="-1">tRPC <a class="header-anchor" href="#trpc" aria-label="Permalink to &quot;tRPC&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>tRPC</td></tr><tr><td><strong>Stars</strong></td><td>⭐ 35,000+</td></tr><tr><td><strong>TS支持</strong></td><td>✅ 原生 TypeScript</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/trpc/trpc" target="_blank" rel="noreferrer">trpc/trpc</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://trpc.io" target="_blank" rel="noreferrer">trpc.io</a></td></tr></tbody></table><p><strong>一句话描述</strong>：端到端类型安全的 RPC 框架，让 API 调用像调用本地函数一样简单。</p><p><strong>核心特点</strong>：</p><ul><li>全自动类型推断，无需代码生成</li><li>与 Zod 等验证库完美集成</li><li>支持订阅（实时数据）</li><li>与 React Query、Svelte 等前端框架集成</li><li>中间件支持</li><li>Batch 请求合并</li></ul><p><strong>适用场景</strong>：</p><ul><li>全栈 TypeScript 项目</li><li>需要类型安全的 API</li><li>前后端紧密协作的团队</li></ul><hr><h3 id="trpc-openapi" tabindex="-1">trpc-openapi <a class="header-anchor" href="#trpc-openapi" aria-label="Permalink to &quot;trpc-openapi&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>trpc-openapi</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/jlalmes/trpc-openapi" target="_blank" rel="noreferrer">jlalmes/trpc-openapi</a></td></tr></tbody></table><p><strong>一句话描述</strong>：为 tRPC 添加 OpenAPI/Swagger 支持，生成 REST API。</p><p><strong>核心特点</strong>：</p><ul><li>从 tRPC 路由生成 OpenAPI 规范</li><li>自动生成 Swagger UI</li><li>支持 RESTful 端点暴露</li></ul><hr><h3 id="ts-rest-core" tabindex="-1">@ts-rest/core <a class="header-anchor" href="#ts-rest-core" aria-label="Permalink to &quot;@ts-rest/core&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性</th><th>详情</th></tr></thead><tbody><tr><td><strong>名称</strong></td><td>ts-rest</td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/ts-rest/ts-rest" target="_blank" rel="noreferrer">ts-rest/ts-rest</a></td></tr><tr><td><strong>官网</strong></td><td><a href="https://ts-rest.com" target="_blank" rel="noreferrer">ts-rest.com</a></td></tr></tbody></table><p><strong>一句话描述</strong>：基于 TypeScript 的契约优先 REST API 框架。</p><p><strong>核心特点</strong>：</p><ul><li>共享契约定义</li><li>支持多种服务端框架（Express、Fastify、Nest 等）</li><li>支持多种客户端（React Query、SWR、Axios 等）</li><li>OpenAPI 生成</li></ul><p><strong>适用场景</strong>：</p><ul><li>需要 REST API 但想要类型安全</li><li>跨团队 API 契约管理</li></ul><hr><h2 id="📈-框架选型建议" tabindex="-1">📈 框架选型建议 <a class="header-anchor" href="#📈-框架选型建议" aria-label="Permalink to &quot;📈 框架选型建议&quot;">​</a></h2><h3 id="按项目类型" tabindex="-1">按项目类型 <a class="header-anchor" href="#按项目类型" aria-label="Permalink to &quot;按项目类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目类型</th><th>推荐框架</th><th>理由</th></tr></thead><tbody><tr><td>传统 Web API</td><td><strong>Express</strong> / <strong>Fastify</strong></td><td>生态丰富，团队熟悉度高</td></tr><tr><td>企业级后端</td><td><strong>NestJS</strong></td><td>架构规范，功能完整</td></tr><tr><td>高性能 API</td><td><strong>Fastify</strong> / <strong>Hono</strong></td><td>性能优异，开销低</td></tr><tr><td>边缘/Serverless</td><td><strong>Hono</strong></td><td>跨平台，边缘优化</td></tr><tr><td>Bun 项目</td><td><strong>Elysia</strong></td><td>Bun 原生优化</td></tr><tr><td>实时应用</td><td><strong>Socket.io</strong> / <strong>ws</strong></td><td>成熟的实时通信方案</td></tr><tr><td>全栈类型安全</td><td><strong>tRPC</strong> / <strong>ts-rest</strong></td><td>端到端类型安全</td></tr></tbody></table><h3 id="按团队背景" tabindex="-1">按团队背景 <a class="header-anchor" href="#按团队背景" aria-label="Permalink to &quot;按团队背景&quot;">​</a></h3><table tabindex="0"><thead><tr><th>团队背景</th><th>推荐框架</th></tr></thead><tbody><tr><td>有 Angular 经验</td><td>NestJS</td></tr><tr><td>追求极致性能</td><td>Fastify、Hono、Elysia</td></tr><tr><td>初创项目快速迭代</td><td>Express、Hono</td></tr><tr><td>大型企业项目</td><td>NestJS、Fastify</td></tr></tbody></table><h3 id="按部署目标" tabindex="-1">按部署目标 <a class="header-anchor" href="#按部署目标" aria-label="Permalink to &quot;按部署目标&quot;">​</a></h3><table tabindex="0"><thead><tr><th>部署目标</th><th>推荐框架</th></tr></thead><tbody><tr><td>传统服务器</td><td>Express、Fastify、NestJS</td></tr><tr><td>Cloudflare Workers</td><td>Hono、Nitro</td></tr><tr><td>Vercel Edge</td><td>Hono、Next.js</td></tr><tr><td>Bun 运行时</td><td>Elysia、Hono</td></tr><tr><td>Deno</td><td>Hono、Oak</td></tr></tbody></table><hr><h2 id="🔗-参考资源" tabindex="-1">🔗 参考资源 <a class="header-anchor" href="#🔗-参考资源" aria-label="Permalink to &quot;🔗 参考资源&quot;">​</a></h2><ul><li><a href="https://fastify.io/" target="_blank" rel="noreferrer">Fastify 官方文档</a></li><li><a href="https://docs.nestjs.com/" target="_blank" rel="noreferrer">NestJS 官方文档</a></li><li><a href="https://hono.dev/" target="_blank" rel="noreferrer">Hono 官方文档</a></li><li><a href="https://elysiajs.com/" target="_blank" rel="noreferrer">Elysia 官方文档</a></li><li><a href="https://trpc.io/" target="_blank" rel="noreferrer">tRPC 官方文档</a></li><li><a href="https://socket.io/" target="_blank" rel="noreferrer">Socket.io 官方文档</a></li><li><a href="https://risingstars.js.org/2025/en" target="_blank" rel="noreferrer">JavaScript Rising Stars 2025</a></li><li><a href="https://stateofjs.com" target="_blank" rel="noreferrer">State of JS 2024</a></li></ul><hr><blockquote><p>📅 本文档最后更新：2026年4月</p><p>💡 提示：Stars 数据会随时间变化，建议查看 GitHub 获取最新数据</p></blockquote>',175)])])}const u=r(d,[["render",s]]);export{p as __pageData,u as default};
